import { GeneratedRoutes, RouteName, MultipleFormatsParams, RoutesNameParams } from '@tuyau/client';

/**
 * To be extended user-side with module augmentation
 */
interface Api {
}
/**
 * Represents a validated API object
 */
type ValidatedApi = Api extends {
    routes: infer Routes extends GeneratedRoutes;
    definition: infer Definition extends Record<string, any>;
} ? {
    routes: Routes;
    definition: Definition;
} : never;
/**
 * Params for the Link component
 */
type LinkParams<T extends RouteName<ValidatedApi['routes']>> = MultipleFormatsParams<RoutesNameParams<ValidatedApi['routes'], T>> extends undefined ? {
    route: T;
    params?: [];
} : {
    route: T;
    params: MultipleFormatsParams<RoutesNameParams<ValidatedApi['routes'], T>>;
};

export type { Api, LinkParams, ValidatedApi };
